var noCacheInterceptor = (req, next) => {
  if (req.method === "GET") {
    const noCacheReq = req.clone({
      setHeaders: {
        "Cache-Control": "no-cache, no-store, must-revalidate",
        "Pragma": "no-cache"
      }
    });
    return next(noCacheReq);
  }
  return next(req);
};

// src/app/app.config.ts
